import React, { useEffect, useState } from "react";
import axios from "axios";

const Service = () => {
  const [services, setServices] = useState([]);
  const [form, setForm] = useState({ MaDV: "", TenDV: "", GiaDV: "" });
  const [search, setSearch] = useState({ TenDV: "", GiaDV: "", sort: "" });
  const [report, setReport] = useState(null);

  const apiBase = "http://localhost:5000/api/service";

  // Load danh sách dịch vụ
  const fetchServices = async () => {
    try {
      const params = Object.fromEntries(Object.entries(search).filter(([_, v]) => v));
      const res = await axios.get(`${apiBase}/managementservices`, { params });
      setServices(res.data);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải danh sách dịch vụ");
    }
  };

  useEffect(() => {
    fetchServices();
  }, []);

  // Thêm / cập nhật dịch vụ
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const exists = services.find(s => s.MaDV === form.MaDV);
      if (exists) {
        await axios.put(`${apiBase}/updateservice`, form);
        alert("Cập nhật dịch vụ thành công");
      } else {
        await axios.post(`${apiBase}/addservice`, form);
        alert("Thêm dịch vụ thành công");
      }
      setForm({ MaDV: "", TenDV: "", GiaDV: "" });
      fetchServices();
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Xóa dịch vụ
  const handleDelete = async (MaDV) => {
    if (!window.confirm("Bạn có chắc muốn xóa dịch vụ này?")) return;
    try {
      await axios.delete(`${apiBase}/deleteservice`, { data: { MaDV } });
      fetchServices();
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Lấy báo cáo dịch vụ
  const fetchReport = async () => {
    try {
      const res = await axios.get(`${apiBase}/reportservice`);
      setReport(res.data);
    } catch (err) {
      alert("Lỗi khi lấy báo cáo dịch vụ");
    }
  };

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">Quản lý dịch vụ</h1>

      {/* Form thêm/sửa */}
      <form className="mb-4 space-y-2" onSubmit={handleSubmit}>
        <input placeholder="Mã DV" value={form.MaDV} onChange={e => setForm({...form, MaDV: e.target.value})} className="border p-2 w-full"/>
        <input placeholder="Tên DV" value={form.TenDV} onChange={e => setForm({...form, TenDV: e.target.value})} className="border p-2 w-full"/>
        <input placeholder="Giá DV" value={form.GiaDV} onChange={e => setForm({...form, GiaDV: e.target.value})} className="border p-2 w-full"/>
        <button type="submit" className="bg-blue-500 text-white px-4 py-2 rounded">
          {services.find(s => s.MaDV === form.MaDV) ? "Cập nhật" : "Thêm dịch vụ"}
        </button>
      </form>

      {/* Tìm kiếm & sắp xếp */}
      <div className="mb-4 space-y-2">
        <h2 className="font-semibold">Tìm kiếm dịch vụ</h2>
        <input placeholder="Tên DV" value={search.TenDV} onChange={e => setSearch({...search, TenDV: e.target.value})} className="border p-2 w-full"/>
        <input placeholder="Giá DV" value={search.GiaDV} onChange={e => setSearch({...search, GiaDV: e.target.value})} className="border p-2 w-full"/>
        <select value={search.sort} onChange={e => setSearch({...search, sort: e.target.value})} className="border p-2 w-full">
          <option value="">Sắp xếp</option>
          <option value="GiaDV">Theo giá</option>
          <option value="TenDV">Theo tên</option>
        </select>
        <button onClick={fetchServices} className="bg-green-500 text-white px-4 py-2 rounded">Tìm kiếm / Sắp xếp</button>
      </div>

      {/* Danh sách dịch vụ */}
      <table className="border w-full text-left mb-4">
        <thead>
          <tr className="bg-gray-200">
            <th className="border px-2 py-1">Mã DV</th>
            <th className="border px-2 py-1">Tên DV</th>
            <th className="border px-2 py-1">Giá DV</th>
            <th className="border px-2 py-1">Hành động</th>
          </tr>
        </thead>
        <tbody>
          {services.map(s => (
            <tr key={s.MaDV}>
              <td className="border px-2 py-1">{s.MaDV}</td>
              <td className="border px-2 py-1">{s.TenDV}</td>
              <td className="border px-2 py-1">{s.GiaDV}</td>
              <td className="border px-2 py-1">
                <button onClick={() => setForm(s)} className="bg-yellow-400 px-2 py-1 mr-2 rounded">Sửa</button>
                <button onClick={() => handleDelete(s.MaDV)} className="bg-red-500 px-2 py-1 rounded text-white">Xóa</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* Báo cáo dịch vụ */}
      <div>
        <button onClick={fetchReport} className="bg-purple-500 text-white px-4 py-2 rounded mb-2">Xem báo cáo dịch vụ</button>
        {report && (
          <div className="mt-2">
            <p><strong>Tổng số dịch vụ:</strong> {report["Tổng số dịch vụ"]}</p>
            <p><strong>Dịch vụ dùng nhiều nhất:</strong> {report["Dịch vụ dùng nhiều nhất"] !== "Chưa có dữ liệu" ? `${report["Dịch vụ dùng nhiều nhất"].TenDV} (${report["Dịch vụ dùng nhiều nhất"].TongSD})` : "Chưa có dữ liệu"}</p>
            <p><strong>Dịch vụ dùng ít nhất:</strong> {report["Dịch vụ dùng ít nhất"] !== "Chưa có dữ liệu" ? `${report["Dịch vụ dùng ít nhất"].TenDV} (${report["Dịch vụ dùng ít nhất"].TongSD})` : "Chưa có dữ liệu"}</p>
          </div>
        )}
      </div>
    </div>
  );
};

// Cuối file Services.jsx
export default Service;
